package com.raonmate.backend.notification.domain; import com.raonmate.backend.workshop.domain.Workshop; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID; @Entity @Table(name="workshop_notifications") public class WorkshopNotification{@Id private UUID id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="workshop_id",nullable=false)private Workshop workshop;@Column(nullable=false,length=30)private String channel;@Column(nullable=false)private int recipientCount;@Column(nullable=false,length=1000)private String message;@Column(nullable=false,length=30)private String status;@Column(nullable=false)private Instant sentAt;protected WorkshopNotification(){}public WorkshopNotification(Workshop w,String c,int r,String m){id=UUID.randomUUID();workshop=w;channel=c;recipientCount=r;message=m;status="SENT";sentAt=Instant.now();}public UUID getId(){return id;}public Workshop getWorkshop(){return workshop;}public String getChannel(){return channel;}public int getRecipientCount(){return recipientCount;}public String getMessage(){return message;}public String getStatus(){return status;}public Instant getSentAt(){return sentAt;}}
